# HOTL: execute with interrupt capability
import asyncio, anthropic, json
from typing import Callable, Any

client = anthropic.AsyncAnthropic()

class HOTLSession:
    """Wraps an agent run with a real-time interrupt channel."""
    def __init__(self):
        self._stop = asyncio.Event()
        self._log: list[dict] = []

    def interrupt(self) -> None:
        """Call from the monitoring UI to stop the agent immediately."""
        self._stop.set()

    @property
    def log(self) -> list[dict]:
        return list(self._log)

    async def run(
        self,
        task:     str,
        tools:    list[dict],
        executor: Callable[[str, dict], Any],
        rollback: Callable[[str, str, dict], None] | None = None,
    ) -> str:
        messages = [{"role": "user", "content": task}]
        executed: list[tuple[str, str, dict]] = []  # (tool_use_id, name, args)

        while True:
            if self._stop.is_set():
                if rollback:
                    for uid, name, args in reversed(executed):
                        try:
                            rollback(uid, name, args)
                        except Exception as e:
                            print(f"Rollback failed for {name}: {e}")
                return "Session interrupted by human reviewer. Actions rolled back."

            response = await client.messages.create(
                model="claude-opus-4-8",
                max_tokens=2048,
                tools=tools,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                return next(b.text for b in response.content if b.type == "text")

            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                if self._stop.is_set():
                    break

                result = await executor(block.name, block.input)
                executed.append((block.id, block.name, block.input))
                self._log.append({
                    "id": block.id, "name": block.name,
                    "input": block.input, "output": result,
                })
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })

            messages.append({"role": "user", "content": tool_results})

# Usage:
# session = HOTLSession()
# task_handle = asyncio.create_task(session.run(task, tools, executor, rollback))
# ... later, from Slack command or dashboard:
# session.interrupt()

# Human-as-Tool: the agent asks targeted questions via a tool
import asyncio, anthropic, json
from typing import Callable, Awaitable

client = anthropic.AsyncAnthropic()

CLARIFY_TOOL = {
    "name": "clarify_question",
    "description": (
        "Ask the human user a targeted question when you need specific information "
        "or a subjective decision that you cannot determine from context. "
        "Use only when genuinely uncertain — not for confirmation of obvious steps."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "question": {
                "type": "string",
                "description": "The specific question to ask. Be concrete and answerable.",
            },
            "options": {
                "type": "array",
                "items": {"type": "string"},
                "description": "If the answer is one of a known set, list the options.",
            },
        },
        "required": ["question"],
    },
}

async def run_human_as_tool(
    task:          str,
    domain_tools:  list[dict],
    ask_human:     Callable[[str, list[str] | None], Awaitable[str]],
    executor:      Callable[[str, dict], Awaitable[dict]],
) -> str:
    tools = [CLARIFY_TOOL] + domain_tools
    messages = [{"role": "user", "content": task}]

    while True:
        response = await client.messages.create(
            model="claude-opus-4-8",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if b.type == "text")

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            if block.name == "clarify_question":
                answer = await ask_human(
                    block.input["question"],
                    block.input.get("options"),
                )
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": answer,
                })
            else:
                result = await executor(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })

        messages.append({"role": "user", "content": tool_results})
